  baseUrl="/clients"
  columnDefs={clientColumnDefs}
  columnsConfig={clientColumnsConfig}
  usersData={data}
  domain="clients"
  filtersToInput={filtersToBaseInput}
  getRowId={(row) => String(row.id)}
  label="Clients"
  listProcedure={{
    queryOptions: (opts) =>
      rpc.client.list.queryOptions({
        input: opts.input as ClientListInput,
      }) as UseQueryOptions,
  }}
  onRowClick={(client) =>
    navigate({
      params: { clientId: String(client.id) },
      to: "/clients/$clientId",
    })
  }
  searchPlaceholder="Search clients..."
/>
```

**Key props breakdown:**

| Prop | Value | Description |
|------|-------|-------------|
| `usersData` | `data` from `rpc.users.list.queryOptions({ input: { limit: 100 } })` | `{ items: Array<{ id, image, name }> }` -- used to populate assignee filter options with avatars |
| `columnsConfig` | `clientColumnsConfig` (from `-view-config.tsx`) | Array of 6 `ColumnConfig<ClientItem>` items: name (text), legalName (text), slug (text), assigneeId (option), archived (option), createdAt (date) |
| `domain` | `"clients"` | String identifying the domain for filter view lookups |
| `filtersToInput` | `filtersToBaseInput` | Converts `FiltersState` -> `{ archived?, assigneeId? }` (the server query params) |

The `filtersToBaseInput` function:
```ts
function filtersToBaseInput(filters: FiltersState) {
  let archived: boolean | undefined;
  let assigneeId: string[] | undefined;
  for (const f of filters) {
    if (f.columnId === "archived" && f.type === "option") {
      archived = f.values[0] === "true";
    }
    if (f.columnId === "assigneeId" && f.type === "option") {
      assigneeId = [...f.values];
    }
  }
  return { archived, assigneeId } satisfies Omit<ClientListInput, "cursor" | "limit" | "search">;
}
```

**Other route pages (tasks, contracts, job-mandates, reports) do NOT use DataViewLayout** -- they each have their own custom layouts.

---

## 5. `FilterViewRow` Type -- Where Defined

`FilterViewRow` is defined in **one place only:**

**File:** `/home/aditya/projects/alpauls-ats/src/components/layouts/data-view-layout.tsx` (line 37):
```ts
type FilterViewRow = {
  createdAt: Date | null;
  display: FilterViewDisplay;
  domain: string;
  id: string;
  isSystemCreated: boolean;
  label: string;
  refine: FiltersState;
  updatedAt: Date | null;
};
```

It is a **local type** -- not exported, not defined in db-schemas, not in the RPC layer. It is used on line 180 to cast the RPC response:
```ts
const filterViews = (filterViewsData ?? []) as FilterViewRow[];
```

There is also a similar `FilterViewTab` type in `filter-view-tabs.tsx` (line 35), but it has fewer fields (no `createdAt`/`updatedAt`).

**Neither `FilterViewRow` nor `FilterViewTab` are defined in db-schemas or rpc.** The db-schema exports `FilterViewDisplay` (the display JSON type) and the `filterViews` Drizzle table, but not a row type.

---

## 6. FilterView DB Schema

**File:** `/home/aditya/projects/alpauls-ats/src/db-schemas/filter-view.ts` (35 lines)

```ts
export type FilterViewDisplay = {
  type: string;
  groupBy: string | null;
  orderBy: string;
  orderType: string;
  fields: string[];
};

export type FilterViewDomain = "clients" | "prospects";

export const filterViews = pgTable(
  "filter_views",
  {
    createdAt: timestamp("created_at").defaultNow(),
    display: jsonb("display").$type<FilterViewDisplay>().notNull(),
    domain: text().notNull().default("clients"),
    id: text().primaryKey(),
    isSystemCreated: boolean("is_system_created").notNull().default(true),
    label: text().notNull(),
    refine: jsonb("refine").$type<FiltersState>().notNull(),
    updatedAt: timestamp("updated_at").defaultNow(),
  },
  (table) => [index("filter_views_domain_idx").on(table.domain)],
);
```

Key points:
- The `refine` column stores `FiltersState` as JSONB (reuses the filter component's type directly)
- The `display` column stores `FilterViewDisplay` as JSONB (view layout metadata)
- Index on `domain` for efficient lookups
- `id` is a text primary key (UUIDs generated at insert time)
- Re-exported via `src/db-schemas/index.ts`

---

## 7. RPC Client Return Type for `filterView.list`

**File:** `/home/aditya/projects/alpauls-ats/src/rpc/client.ts`

The RPC client is isomorphic:
```ts
const getORPCClient = createIsomorphicFn()
  .server(() => createRouterClient(router, { ... }))
  .client((): RouterClient<typeof router> => { ... });

export const client: RouterClient<typeof router> = getORPCClient();
export const rpc = createTanstackQueryUtils(client);
```

The `rpc.filterView.list` procedure (from `/home/aditya/projects/alpauls-ats/src/rpc/router/filter-view.ts`):
```ts
export const filterViewList = protectedProcedure
  .meta({ permission: { action: "read", resource: "filter_views" } })
  .input(listFilterViewsSchema)  // { domain: z.string() }
  .handler(async ({ input }) => {
    return db.select().from(filterViews).where(eq(filterViews.domain, input.domain));
  });
```

The return type is inferred from Drizzle's `db.select().from(filterViews)` -- it returns an **array of rows** matching the table schema. Since the RPC client is typed via `RouterClient<typeof router>`, the return type of `rpc.filterView.list` is:

```ts
Array<{
  createdAt: Date | null;
  display: FilterViewDisplay;  // from the jsonb $type
  domain: string;
  id: string;
  isSystemCreated: boolean;
  label: string;
  refine: FiltersState;  // from the jsonb $type
  updatedAt: Date | null;
}>
```

(This is exactly the shape that `FilterViewRow` in `data-view-layout.tsx` manually defines, confirming the cast is safe.)

---

## 8. Existing Filter Manipulation Utilities

### In `data-view-layout.tsx` (lines 52-103) -- **the only place with merge/compute logic:**

```ts
function filterKey(f: FiltersState[number]) {
  return `${f.columnId}::${f.operator}`;
}

function filtersEqual(a: FiltersState[number], b: FiltersState[number]) {
  return (
    a.columnId === b.columnId &&
    a.operator === b.operator &&
    a.type === b.type &&
    a.values.length === b.values.length &&
    a.values.every((v, i) => v === b.values[i])
  );
}

function mergeFilters(base: FiltersState, overrides: FiltersState) {
  // Merges overrides into base. Override wins by key. New overrides appended.
  const overrideMap = new Map(overrides.map((o) => [filterKey(o), o]));
  const result: FiltersState = [];
  for (const b of base) {
    const key = filterKey(b);
    if (overrideMap.has(key)) {
      const override = overrideMap.get(key);
      if (override && !filtersEqual(b, override)) result.push(override);
      overrideMap.delete(key);
    } else {
      result.push(b);
    }
  }
  for (const o of overrideMap.values()) result.push(o);
  return result;
}

function computeOverrides(base: FiltersState, effective: FiltersState) {
  // Computes the diff: which filters in effective differ from base
  const overrides: FiltersState = [];
  const baseMap = new Map(base.map((b) => [filterKey(b), b]));
  for (const f of effective) {
    const key = filterKey(f);
    const baseFilter = baseMap.get(key);
    if (!baseFilter || !filtersEqual(baseFilter, f)) overrides.push(f);
  }
  return overrides;
}
```

**These are NOT exported** -- they are private functions used only within `DataViewLayout`.

### In `data-table-filter/lib/array.ts`:
- `intersection(a, b)` -- used by filter-fns for multiOption matching
- `uniq(arr)` -- deep-dedup using hash + equality
- `addUniq(arr, values)` -- union of unique items
- `removeUniq(arr, values)` -- subtract values
- `isAnyOf(value, values)` -- includes check

### In `data-table-filter/lib/helpers.ts`:
- `getColumn(columns, id)` -- lookup column by ID
- `createNumberFilterValue(values)` -- normalizes number ranges
- `createDateFilterValue(values)` -- normalizes date ranges
- `isColumnOption(value)` / `isColumnOptionArray(value)` / `isColumnOptionMap(value)` / `isMinMaxTuple(value)` -- type guards

### In `data-table-filter/core/operators.ts`:
- `determineNewOperator(type, oldVals, nextVals, currentOperator)` -- transitions operator between singular/plural forms when value count changes

### In `data-table-filter/core/filters.ts`:
- `createColumnConfigHelper<TData>()` -- fluent builder for ColumnConfig
- `createColumns(data, columnConfigs, strategy)` -- converts ColumnConfig[] -> Column[] with memoized accessors
- `getColumnOptions(column, data, strategy)` -- resolves options for option/multiOption columns
- `getColumnValues(column, data)` -- extracts raw values
- `getFacetedUniqueValues(column, values, strategy)` -- computes faceted counts
- `getFacetedMinMaxValues(column, data, strategy)` -- computes number ranges

### In `src/lib/filter-views.ts`:
- Static seed data defining system filter views (not utility functions):
```ts
export const filterViews = [
  { id: "clients-active", domain: "clients", label: "Active", isSystemCreated: true, ... },
  { id: "clients-archived", domain: "clients", label: "Archived", isSystemCreated: true, ... },
];
export type FilterViewId = (typeof filterViews)[number]["id"];
```

### In `scripts/seed-filter-views.ts`:
- `deepEqual(a, b)` -- a local deep equality function for comparing seed data against DB rows (not exported/imported elsewhere)

**Summary:** There are **no standalone exported utility modules** for filter manipulation (merge, compute, transform) anywhere in the codebase. The `mergeFilters` and `computeOverrides` functions exist only as private functions inside `data-view-layout.tsx`. The `data-table-filter/lib/` directory has array helpers, type guards, and value constructors, but nothing for merging or computing filter diffs.
