import {
  flexRender,
  getCoreRowModel,
  useReactTable,
} from "@tanstack/react-table";
import { Search } from "lucide-react";
import { useEffect, useState } from "react";

import { DataTableFilter } from "@/components/data-table-filter";
import type {
  ColumnConfig,
  ColumnOption,
  FiltersState,
