import type { FiltersState } from "@/components/data-table-filter/core/types";

// Prefix prevents TanStack Router's parseSearch from auto-parsing the JSON
// value, which would corrupt the FiltersState array through the nuqs adapter.
const FILTERS_PREFIX = "~";

export const filtersUrlParser = createParser<FiltersState>({
    parse: (query) => {
        try {
            const json = query.startsWith(FILTERS_PREFIX)
                ? query.slice(FILTERS_PREFIX.length)
                : query;
            const parsed = JSON.parse(json);
            return Array.isArray(parsed) ? parsed : null;
        } catch {
