export function useFilterViewState(domain: string) {
  const router = useRouter();
  const navigate = useNavigate();

  const search = router.state.location.search as Record<string, unknown>;
  const view = typeof search.view === "string" ? search.view : "";
  const rawFilters = search.filters;
  const urlFilters = Array.isArray(rawFilters) ? rawFilters as FiltersState : [];

  // ... filter view query ...

  const effectiveFilters = view
    ? mergeFilters(baseFilters, urlFilters)
    : urlFilters;

  const updateFilters = (next) => {
    const resolved = typeof next === "function" ? next(effectiveFilters) : next;

    if (view) {
