      <body className="bg-sidebar">
        <NuqsAdapter>
          <PostHogProvider>
            <TooltipProvider>{children}</TooltipProvider>
            <Devtools />
          </PostHogProvider>
        </NuqsAdapter>
        <Scripts />
      </body>
    </html>
  );
}

